#!/usr/bin/env bash
# Emit RTL and optional GHDL trace into verifylog/ (see verifylog/README.md).
set -euo pipefail
ROOT="$(cd "$(dirname "$0")/.." && pwd)"
cd "$ROOT"

STAMP="${VERIFYLOG_STAMP:-$(git rev-parse --short HEAD 2>/dev/null || echo local)}"
OUT="$ROOT/verifylog/ref-runs/$STAMP"
mkdir -p "$OUT"

cargo run --quiet --manifest-path "$ROOT/rtl-bridge/Cargo.toml" --bin gnosis-rtl-emit
cp -f "$ROOT/verifylog/vhdl/gnosis_resolution_lift_fsm_v0.vhd" "$OUT/" 2>/dev/null || true
cp -f "$ROOT/verifylog/vhdl/gnosis_resolution_lift_fsm_v0.sv" "$OUT/" 2>/dev/null || true

if [[ "${GNOSIS_RTL_TOOLS:-}" == "1" ]] && command -v ghdl >/dev/null 2>&1; then
  bash "$ROOT/scripts/ghdl-sim-rtl-bridge.sh"
  cp -f "$ROOT/verifylog/traces/ghdl-resolution-lift.log" "$OUT/" 2>/dev/null || true
fi

echo "{\"stamp\":\"$STAMP\",\"emit\":\"ok\"}" >"$OUT/summary.json"
echo "verifylog-populate: wrote $OUT/summary.json"
